Yeah, I actually followed the leads from that code , The WriteProperty is working fine for me as of now (though not extensively tested, still under development).

```
class BacnetScheduleObject(ScheduleObject):
    def __init__(self, **kwargs):
        super(BacnetScheduleObject, self).__init__(**kwargs)

    def ReadProperty(self, propid, arrayIndex=None):
        return super(BacnetScheduleObject, self).ReadProperty(propid,
                                                             arrayIndex)

    def WriteProperty(self, propid, value, arrayIndex=None, priority=None, direct=False):
        if propid in ["weeklySchedule", "exceptionSchedule"]:
            if propid == 'weeklySchedule':
                value = ArrayOf(DailySchedule)(value)
            elif propid == "exceptionSchedule":
                value = ArrayOf(SpecialEvent)(value)
        return super(BacnetScheduleObject, self).WriteProperty(propid, value, arrayIndex, priority, direct)


    @classmethod
    def make_mutable(cls):
        for prop in cls.properties[:]:
            if isinstance(prop, OptionalProperty):
                prop.mutable = True
            elif prop.identifier == "priorityForWriting":
                prop.mutable = True
```

